var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"......솔직히 말해서, 놀랍군.","JPN":"……正直に言って、驚いた。","ENG":"Honestly, I’m most impressed.","TWN":"……說實話，這真是令人驚訝。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"이 정도의 군세를 끌고 왔는데도 겨우 호각세라니.","JPN":"これほどの軍勢を率いてきたのに、互角とは。","ENG":"I’ve brought a considerable force with me, yet you still manage to hold your ground.","TWN":"調來了這麼多兵力，結果好不容易才打成了平手。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"실로 기사의 싸움에 걸맞은 훌륭한 적이다. 경의를 표하지.","JPN":"まさしく騎士の戦いにふさわしい\\n立派な相手だ。敬意を表する。","ENG":"You are indeed a worthy enemy for a knight. Allow me to convey my respect.","TWN":"確實是值得與騎士一戰的敵人，值得敬佩。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......정신 나간 놈이군.","JPN":"……とんだ勘違い野郎だな。","ENG":"Okay, Don Quixote.","TWN":"……真是個瘋子。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"코드네임이 나이트라고 해서 정말 기사라도 된 기분인가?","JPN":"コードネームがナイトだからって、本当に騎士にでもなったつもりか？","ENG":"You think you're a real knight just because they gave you that code name?","TWN":"因為代碼名是Knight，所以也可以叫作騎士嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"하하, 도발하는 건가? 전사여.","JPN":"ハハ、それは挑発か？　戦士よ。","ENG":"Haha, are you trying to provoke me? Most worthy foe.","TWN":"哈哈，妳是在挑釁嗎？戰士。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"허나 마음대로 비웃어도 좋다.","JPN":"しかし、好きなだけあざ笑うが良い。","ENG":"Ridicule me all you want.","TWN":"不過妳就盡情地嘲笑吧。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"난 지금 진실로 너희에게 감사하고 있으니까.","JPN":"私は今、本気で貴様らに感謝をしているからな。","ENG":"That won’t diminish the gratitude I have for you right now.","TWN":"因為我現在是真的很感謝你們。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"또 무슨 헛소리를......","JPN":"また戯言を……","ENG":"What kind of a crazy talk is this...","TWN":"這又是在說什麼……"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"애당초 난 기습이나 암살 같은 임무에 걸맞지 않는다.","JPN":"そもそも私は、奇襲や暗殺のような任務には適していない。","ENG":"I was never designed for ambushes or assassinations in the first place.","TWN":"我本來就不適合偷襲或者暗殺的任務。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"내 모체가 나에게 가르쳐 준 것은 단 하나.","JPN":"私の母体が私に教えてくれたことはただ一つ。","ENG":"There is only one thing my source has taught me.","TWN":"我的母體教我的事情只有一個。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"전투의 기쁨.","JPN":"戦うことの悦び。","ENG":"The ecstasy of battle.","TWN":"戰鬥的快感。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"난 지금 그 기쁨을 충분히 누리고 있다.","JPN":"私は今、その悦びを十分に味わっている。","ENG":"And I am indulging myself in such bliss right now.","TWN":"我現在就在盡情享受著這種快感。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 말보다 주먹이라는 뜻인 것 같은데, 왠지 스승님이랑 잘 통할 것 같지 않나요?","JPN":"ハハ、「言葉よりも拳」と言いたいようですが、師匠と通じるところがありそうですね？","ENG":"Haha, sounds like a fancy way of saying “less talk, more fighting.” Don’t you think she’ll get along nicely with you, Master?","TWN":"哈哈，聽起來像是拳頭大於話語的意思，這不是和師父很合得來嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"허나 임무에 실패할 생각은 없다.","JPN":"だが、任務に失敗するつもりはない。","ENG":"Nevertheless, I have no plans to fail my mission.","TWN":"但是，我不會讓任務失敗的。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"내키지는 않지만...... 도움을 요청할 시간이군.","JPN":"気が向かないが……支援を求める時だな。","ENG":"Although I am reluctant... The time has come to call for help.","TWN":"雖然不樂意……但希望您能幫助我。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......도움?","JPN":"……支援？","ENG":"Help?","TWN":"……幫助？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};